def get_map(index_dir=None):
    if not index_dir:
        index_dir = get_default_index_dir()
    map_path = os.path.join(index_dir, "codebase_map.md")
    if not os.path.exists(map_path):
        return f"Error: Codebase map not found at {map_path}. Please run pipeline.py first."
    with open(map_path, "r", encoding="utf-8") as f:
        return f.read()

def query_sql(sql_query, index_dir=None):
    if not index_dir:
        index_dir = get_default_index_dir()

    df = query_engine.query_codebase(sql_query, index_dir)
    if df is not None:
        if df.empty:
            return "Query executed successfully, but returned 0 rows."
        return df.to_string(index=False)
    return "No results or error executing SQL query."

def search_semantic(query, limit=3, index_dir=None):
    if not index_dir:
        index_dir = get_default_index_dir()

    searcher = query_engine.LocalSemanticSearcher(index_dir)
    results = searcher.search(query, limit=limit)
    if not results:
        return "No matching elements found."

    output = []
    for i, res in enumerate(results, 1):
        output.append(f"{i}. Function: {res['name']}")
        output.append(f"   File: {res['file_path']}")
        output.append(f"   Docstring: {res['docstring'].strip() if res['docstring'] else '*None*'}")
        output.append(f"   Score: {res['score']}")
        output.append("-" * 40)
    return "\n".join(output)

def main():
    parser = argparse.ArgumentParser(description="LLM Tool-Calling Interface CLI")
    parser.add_argument("--action", choices=["map", "sql", "search", "view-code"], required=True,
                        help="Action to perform: 'map' (get structure), 'sql' (query DB), 'search' (TF-IDF search), 'view-code' (get source code)")
    parser.add_argument("--query", type=str, help="SQL query for 'sql' action, or search term for 'search' action")
    parser.add_argument("--name", type=str, help="Element name for 'view-code' action")
    parser.add_argument("--type", type=str, choices=["function", "method", "class"], default=None, help="Type filter for 'view-code' action")
    parser.add_argument("--index-dir", type=str, default=None, help="Optional custom .llm_index directory path")

    args = parser.parse_args()

    if args.action == "map":
        print(get_map(args.index_dir))
    elif args.action == "sql":
        if not args.query:
            print("Error: --query is required for 'sql' action.")
            sys.exit(1)
        print(query_sql(args.query, args.index_dir))
    elif args.action == "search":
        if not args.query:
            print("Error: --query is required for 'search' action.")
            sys.exit(1)
        print(search_semantic(args.query, index_dir=args.index_dir))
    elif args.action == "view-code":
        if not args.name:
            print("Error: --name is required for 'view-code' action.")
            sys.exit(1)
        print(get_code_element(args.name, args.type, args.index_dir))

def visit_Import(self, node):
        for alias in node.names:
            self.imports.append({
                "name": alias.name,
                "asname": alias.asname,
                "line": node.lineno
            })
        self.generic_visit(node)

def visit_ImportFrom(self, node):
        module = node.module or ""
        for alias in node.names:
            self.imports.append({
                "name": f"{module}.{alias.name}" if module else alias.name,
                "asname": alias.asname,
                "line": node.lineno
            })
        self.generic_visit(node)

def visit_ClassDef(self, node):
        bases = []
        for base in node.bases:
            if isinstance(base, ast.Name):
                bases.append(base.id)
            elif isinstance(base, ast.Attribute):
                bases.append(self._get_attribute_name(base))
            else:
                bases.append("Unknown")

        docstring = ast.get_docstring(node) or ""

        self.classes.append({
            "name": node.name,
            "bases": bases,
            "docstring": docstring,
            "line_start": node.lineno,
            "line_end": getattr(node, "end_lineno", node.lineno)
        })

        old_class = self.current_class
        self.current_class = node.name
        self.generic_visit(node)
        self.current_class = old_class

def _extract_function(self, node):
        docstring = ast.get_docstring(node) or ""

        # Parse arguments with type hints
        args = []
        for arg in node.args.args:
            annotation = ""
            if arg.annotation:
                annotation = self._get_annotation_str(arg.annotation)
            args.append(f"{arg.arg}: {annotation}" if annotation else arg.arg)

        returns = ""
        if node.returns:
            returns = self._get_annotation_str(node.returns)

        # Safely extract exact source segment
        try:
            source_code = ast.get_source_segment(self.source_code, node) or ""
        except Exception:
            # Fallback line slicing if segment fails
            lines = self.source_code.splitlines()
            start = node.lineno - 1
            end = getattr(node, "end_lineno", len(lines))
            source_code = "\n".join(lines[start:end])

        # Analyze internal function calls
        called_functions = []
        for child in ast.walk(node):
            if isinstance(child, ast.Call):
                func_name = self._get_call_name(child.func)
                if func_name:
                    called_functions.append(func_name)

        self.functions.append({
            "name": node.name,
            "class_name": self.current_class,
            "args": args,
            "returns": returns,
            "docstring": docstring,
            "calls": list(set(called_functions)),
            "line_start": node.lineno,
            "line_end": getattr(node, "end_lineno", node.lineno),
            "source_code": source_code
        })

def _get_annotation_str(self, node):
        try:
            if isinstance(node, ast.Name):
                return node.id
            elif isinstance(node, ast.Attribute):
                return self._get_attribute_name(node)
            elif isinstance(node, ast.Subscript):
                value = self._get_annotation_str(node.value)
                slice_val = self._get_annotation_str(node.slice)
                return f"{value}[{slice_val}]"
            elif isinstance(node, ast.Tuple):
                elements = [self._get_annotation_str(el) for el in node.elts]
                return ", ".join(elements)
            elif isinstance(node, ast.List):
                elements = [self._get_annotation_str(el) for el in node.elts]
                return f"[{', '.join(elements)}]"
            elif isinstance(node, ast.Constant):
                return str(node.value)
            elif isinstance(node, ast.BinOp) and isinstance(node.op, ast.BitOr):
                left = self._get_annotation_str(node.left)
                right = self._get_annotation_str(node.right)
                return f"{left} | {right}"
        except Exception:
            pass
        return "Unknown"

def _get_attribute_name(self, node):
        parts = []
        curr = node
        while isinstance(curr, ast.Attribute):
            parts.append(curr.attr)
            curr = curr.value
        if isinstance(curr, ast.Name):
            parts.append(curr.id)
        return ".".join(reversed(parts))

def _get_call_name(self, node):
        if isinstance(node, ast.Name):
            return node.id
        elif isinstance(node, ast.Attribute):
            return self._get_attribute_name(node)
        return None

def scan_directory(target_dir):
    """
    Scans a directory recursively and parses all Python files found.
    """
    all_files = []
    all_classes = []
    all_functions = []

    for root, _, filenames in os.walk(target_dir):
        # Ignore common directories to avoid noise
        if any(ignored in root for ignored in [".git", "__pycache__", ".venv", ".llm_index"]):
            continue

        for filename in filenames:
            if filename.endswith(".py"):
                abs_path = os.path.join(root, filename)
                res = parse_file(abs_path, root_dir=target_dir)
                if res:
                    all_files.append(res["file"])
                    all_classes.extend(res["classes"])
                    all_functions.extend(res["functions"])

    return {
        "files": all_files,
        "classes": all_classes,
        "functions": all_functions
    }

def convert_to_parquet(data_list, output_path, fallback_cols):
    """
    Converts list of dictionaries to Parquet file using pandas and pyarrow.
    Enforces basic columns to guarantee consistent schemas.
    """
    if not data_list:
        df = pd.DataFrame(columns=fallback_cols)
    else:
        df = pd.DataFrame(data_list)
        # Ensure all fallback columns exist
        for col in fallback_cols:
            if col not in df.columns:
                df[col] = None

    # Write as Parquet
    df.to_parquet(output_path, engine="pyarrow", index=False)

def __init__(self, index_dir):
        self.index_dir = index_dir
        self.funcs_df = query_codebase("SELECT name, file_path, docstring, source_code FROM functions", index_dir)

def search(self, query_text, limit=3):
        """
        Executes a simple tf-idf string overlap and keyword similarity search
        over docstrings and function names.
        """
        if self.funcs_df is None or self.funcs_df.empty:
            return []

        query_words = set(query_text.lower().split())
        results = []

        for _, row in self.funcs_df.iterrows():
            name = row["name"].lower()
            doc = str(row["docstring"]).lower()

            score = 0
            # Name match (highest weight)
            for word in query_words:
                if word in name:
                    score += 10
                if word in doc:
                    score += 2

            if score > 0:
                results.append({
                    "name": row["name"],
                    "file_path": row["file_path"],
                    "docstring": row["docstring"],
                    "source_code": row["source_code"],
                    "score": score
                })

        # Sort by score descending
        results.sort(key=lambda x: x["score"], reverse=True)
        return results[:limit]

